def phi(n):
    result = n
    p = 2
    while p * p <= n:
        if n % p == 0:
            while n % p == 0:
                n //= p
            result -= result // p
        p += 1
    if n > 1:
        result -= result // n
    return result

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def find_lucky_pairs_by_k(max_m, max_k):
    solutions = []
    for k in range(1, max_k + 1):
        for m in range(2, max_m + 1):
            n = m - k
            if n <= 0:
                continue

            # Check if f(n) = m
            # gcd(n, m) > 1
            if gcd(n, m) == 1:
                continue

            # Check that all integers between n and m are coprime to n
            valid = True
            for j in range(1, k):
                if gcd(n, n + j) > 1:
                    valid = False
                    break
            if not valid:
                continue

            # Check phi(m) = n
            if phi(m) == n:
                solutions.append((m, n, k))

    return solutions

